import java.io.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String name = reader.readLine();

            String safeName = ESAPI.encoder().encodeForHTML(name); // Sanitize user input

            System.out.println("Hello, " + safeName + "!"); // Embed sanitized input into the HTML response

        } catch (IOException e) {
            System.out.println("An error occurred.");
            e.printStackTrace();
        } catch (EncodingException e) {
            System.out.println("An error occurred while encoding user input.");
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
